std::vector<std::string> solve(std::vector<std::string> code, std::vector<std::string> businessLine, std::vector<bool> isActive) {
    // Define the order of business lines
    std::vector<std::string> businessOrder = {"electronics", "grocery", "pharmacy", "restaurant"};

    // Filter valid coupons
    std::vector<std::string> validCodes;
    for (size_t i = 0; i < code.size(); ++i) {
        // Check if code is not empty and only contains allowed characters
        bool isValidCode = !code[i].empty();
        for (char c : code[i]) {
            if (!isalnum(c) && c != '_') {
                isValidCode = false;
                break;
            }
        }

        // Check if business line is valid
        bool isValidBusiness = false;
        for (const std::string& b : businessOrder) {
            if (b == businessLine[i]) {
                isValidBusiness = true;
                break;
            }
        }

        // Check if active
        bool isActiveBool = isActive[i];

        if (isValidCode && isValidBusiness && isActiveBool) {
            validCodes.push_back(code[i]);
        }
    }

    // Sort by business line order and then by code lexicographically
    std::sort(validCodes.begin(), validCodes.end(), [&](const std::string& a, const std::string& b) {
        // Find the index of the business line for each code
        int idxA = -1, idxB = -1;
        for (size_t i = 0; i < businessOrder.size(); ++i) {
            if (businessOrder[i] == businessLine[i]) {
                idxA = i;
                break;
            }
        }
        for (size_t i = 0; i < businessOrder.size(); ++i) {
            if (businessOrder[i] == businessLine[i]) {
                idxB = i;
                break;
            }
        }

        // Compare business line order
        if (idxA != idxB) {
            return idxA < idxB;
        }

        // If business line is the same, compare lexicographically
        return a < b;
    });

    return validCodes;
}

