from typing import List

def solve(code: List[str], businessLine: List[str], isActive: List[bool]) -> List[str]:
    # Define the order of business lines
    business_order = ["electronics", "grocery", "pharmacy", "restaurant"]

    # Filter valid coupons
    valid_codes = []
    for i in range(len(code)):
        # Check if code is not empty and only contains allowed characters
        is_valid_code = not code[i].empty()
        for c in code[i]:
            if not (c.isalnum() or c == '_'):
                is_valid_code = False
                break

        # Check if business line is valid
        is_valid_business = False
        for b in business_order:
            if b == businessLine[i]:
                is_valid_business = True
                break

        # Check if active
        is_active = isActive[i]

        if is_valid_code and is_valid_business and is_active:
            valid_codes.append(code[i])

    # Sort by business line order and then by code lexicographically
    def sort_key(code_str: str) -> tuple:
        # Find the index of the business line for the code
        idx = -1
        for i, b in enumerate(business_order):
            if b == businessLine[i]:
                idx = i
                break
        return (idx, code_str)

    valid_codes.sort(key=sort_key)

    return valid_codes
